@@ -119,6 +119,13 @@ asx_status asx_quiescence_check(asx_region_id id) {
     return asx_region_obligations_resolved(id);
 }

+int asx_region_is_quiescent(asx_region_id id) {
+    asx_quiescence_report report;
+
+    if (asx_quiescence_check_detailed(id, &report) != ASX_OK) return 0;
+    return report.quiescent;
+}
+
 /* -------------------------------------------------------------------
  * Detailed quiescence check with Q1-Q4 decomposition (bd-1eqo.5.2)
  * ------------------------------------------------------------------- */

@@ -64,6 +64,7 @@ static int runtime_has_pending_obligations(void) {
     uint32_t i;

     for (i = 0; i < g_obligation_count; i++) {
+        /* ASX_CHECKPOINT_WAIVER("bounded arena scan over static obligation slots") */
         if (!g_obligations[i].alive) continue;
         if (g_obligations[i].state == ASX_OBLIGATION_RESERVED) return 1;
     }
@@ -75,6 +76,7 @@ static int runtime_has_pending_region_cleanup(void) {
     uint32_t i;

     for (i = 0; i < g_region_count; i++) {
+        /* ASX_CHECKPOINT_WAIVER("bounded arena scan over static region slots") */
         if (!g_regions[i].alive) continue;
         if (asx_cleanup_pending(&g_regions[i].cleanup) != 0u) return 1;
     }
@@ -86,6 +88,7 @@ static int runtime_all_regions_closed(void) {
     uint32_t i;

     for (i = 0; i < g_region_count; i++) {
+        /* ASX_CHECKPOINT_WAIVER("bounded arena scan over static region slots") */
         if (!g_regions[i].alive) continue;
         if (g_regions[i].state != ASX_REGION_CLOSED) return 0;
     }

@@ -678,6 +678,7 @@ static void scenario_quiescence_evidence(void) {

     /* Cross-validate with basic quiescence check */
     SCENARIO_CHECK(asx_quiescence_check(rid) == ASX_OK, "basic_quiescence_agrees");
+    SCENARIO_CHECK(asx_region_is_quiescent(rid) == 1, "bool_quiescence_agrees");

     SCENARIO_END();
 }

@@ -480,6 +480,11 @@ TEST(quiescence_detailed_invalid_handle_returns_not_found) {
     ASSERT_EQ(asx_quiescence_check_detailed(bad, &report), ASX_E_NOT_FOUND);
 }

+TEST(region_is_quiescent_invalid_handle_returns_false) {
+    asx_runtime_reset();
+    ASSERT_FALSE(asx_region_is_quiescent(0xDEADBEEFu));
+}
+
 TEST(quiescence_detailed_fully_quiescent) {
     asx_region_id rid;
     asx_region_slot *region = NULL;
@@ -500,6 +505,7 @@ TEST(quiescence_detailed_fully_quiescent) {
     ASSERT_EQ(report.q3_obligations_resolved, 1);
